INSERT INTO post (study_id, user_id, post_type, post_title, post_content, post_delete, post_view_count, post_created_at, post_updated_at) VALUES (1, 1, 'NOTICE', '자바 스터디 첫 공지입니다', '{"time":1750420200000,"blocks":[{"id":"n1b1","type":"header","data":{"text":"첫 모임 안내","level":2}},{"id":"n1b2","type":"paragraph","data":{"text":"7월 1일 오전 9시에 첫 모임을 시작합니다. 많은 참여 부탁드립니다."}},{"id":"n1b3","type":"list","data":{"style":"unordered","items":["장소: 온라인 (Zoom)","준비물: 자바 기초 교재","시간: 오전 9시 ~ 11시"]}}],"version":"2.30.2"}', false, 0, '2026-06-20 10:30:00', '2026-06-20 10:30:00');
INSERT INTO post (study_id, user_id, post_type, post_title, post_content, post_delete, post_view_count, post_created_at, post_updated_at) VALUES (1, 1, 'GENERAL', '자바 Collections 정리', '{"time":1750507200000,"blocks":[{"id":"g1b1","type":"header","data":{"text":"자바 Collections 비교","level":2}},{"id":"g1b2","type":"paragraph","data":{"text":"List, Set, Map의 차이점과 각 구현체별 특징을 정리해봤습니다."}},{"id":"g1b3","type":"list","data":{"style":"unordered","items":["List: 순서 있음, 중복 허용 (ArrayList, LinkedList)","Set: 순서 없음, 중복 불허 (HashSet, TreeSet)","Map: 키-값 쌍, 키 중복 불허 (HashMap, TreeMap)"]}}],"version":"2.30.2"}', false, 0, '2026-06-21 14:00:00', '2026-06-21 14:00:00');
INSERT INTO post (study_id, user_id, post_type, post_title, post_content, post_delete, post_view_count, post_created_at, post_updated_at) VALUES (2, 1, 'QUESTION', 'Spring Security 설정 질문', '{"time":1750514400000,"blocks":[{"id":"q1b1","type":"header","data":{"text":"Spring Security permitAll() 적용 문제","level":2}},{"id":"q1b2","type":"paragraph","data":{"text":"SecurityFilterChain 설정 중 permitAll()이 적용이 안 되는데 혹시 아시는 분 계신가요?"}},{"id":"q1b3","type":"code","data":{"code":"@Bean\npublic SecurityFilterChain filterChain(HttpSecurity http) throws Exception {\n    http.authorizeHttpRequests(auth -> auth\n        .requestMatchers(\"/public/**\").permitAll()\n        .anyRequest().authenticated()\n    );\n    return http.build();\n}"}}],"version":"2.30.2"}', false, 0, '2026-06-21 16:00:00', '2026-06-21 16:00:00');